        Assertions.assertNotNull(response.menuOptions);
        Assertions.assertTrue(response.menuOptions.isEmpty());
        Assertions.assertNull(response.title01);
        Assertions.assertNull(response.title02);
        Assertions.assertNull(response.errorMessage);
