    @Test
    void testMenuResponseFieldAssignment() {
        MenuResponse response = new MenuResponse();
        response.title01 = "AWS CardDemo";
        response.title02 = "Main Menu";
        response.transactionName = "CM00";
        response.programName = "COMEN01C";
        response.currentDate = "2024-01-15";
        response.currentTime = "10:30:00";
        response.errorMessage = null;
        response.menuOptions.add("1. View Account");

        Assertions.assertEquals("AWS CardDemo", response.title01);
        Assertions.assertEquals("Main Menu", response.title02);
        Assertions.assertEquals("CM00", response.transactionName);
        Assertions.assertEquals("COMEN01C", response.programName);
        Assertions.assertEquals("2024-01-15", response.currentDate);
        Assertions.assertEquals("10:30:00", response.currentTime);
        Assertions.assertNull(response.errorMessage);
        Assertions.assertEquals(1, response.menuOptions.size());
        Assertions.assertEquals("1. View Account", response.menuOptions.get(0));
    }

